/* descr.msw -- SNOBOL4 Descriptor Layout for COR24
 *
 * A descriptor is a 2-word (6-byte) tagged value.
 *
 * Word 0 (3 bytes):
 *   byte 0: primary tag     (DESC_TAG)
 *   byte 1: subtype/flags   (DESC_SUB)
 *   byte 2: reserved        (DESC_RSV)
 *
 * Word 1 (3 bytes):
 *   bytes 3-5: payload      (DESC_PAY) -- integer, pointer, or id
 *
 * Descriptors are always copied and compared as 6-byte units.
 * Physical layout is COR24-specific; semantic meaning is portable.
 */

/* --- Tag constants (byte 0) --- */

%DEFINE TAG_NULL     0;
%DEFINE TAG_UNINIT   1;
%DEFINE TAG_INT      2;
%DEFINE TAG_STR      3;
%DEFINE TAG_SYM      4;
%DEFINE TAG_PAT      5;
%DEFINE TAG_LABEL    6;
%DEFINE TAG_BUILTIN  7;
%DEFINE TAG_REAL     8;
%DEFINE TAG_ARRAY    9;
%DEFINE TAG_TABLE    10;
%DEFINE TAG_COUNT    11;

/* --- Subtype / flag bits (byte 1) --- */
/* Low nibble: subtype (type-specific)
 * High nibble: flags
 *   bit 7: GC-forwarded
 *   bit 6: immutable
 *   bit 5: reserved
 *   bit 4: reserved
 */

%DEFINE DFLAG_FWD    128;
%DEFINE DFLAG_IMMUT  64;

/* --- Descriptor size --- */

%DEFINE DESC_BYTES   6;
%DEFINE DESC_WORDS   2;

/* --- Descriptor as BASED record --- */

DCL 1 DESCR BASED,
    3 DTAG   BYTE,
    3 DSUB   BYTE,
    3 DRSV   BYTE,
    3 DPAY   PTR;

/* --- Descriptor access macros ---
 *
 * These macros operate on a descriptor through a pointer.
 *
 * ?DESC_TAG: read tag byte from descriptor at pointer
 *   Input:  PTR(expr) -- pointer to descriptor
 *   Output: inline asm loads tag into r0
 *   Clobbers: r0, r2
 *
 * ?DESC_SET_TAG: write tag byte
 *   Input:  PTR(expr) -- pointer to descriptor
 *           VAL(expr) -- tag value
 *   Clobbers: r0, r1, r2
 */

MACRODEF DESC_TAG;
    REQUIRED PTR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lb      r0,0(r2)';
    END;
END;

MACRODEF DESC_SET_TAG;
    REQUIRED PTR(expr);
    REQUIRED VAL(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lc      r0,{VAL}';
        'sb      r0,0(r2)';
    END;
END;

MACRODEF DESC_SUB;
    REQUIRED PTR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lb      r0,1(r2)';
    END;
END;

MACRODEF DESC_SET_SUB;
    REQUIRED PTR(expr);
    REQUIRED VAL(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lc      r0,{VAL}';
        'sb      r0,1(r2)';
    END;
END;

MACRODEF DESC_PAY;
    REQUIRED PTR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lw      r0,3(r2)';
    END;
END;

MACRODEF DESC_SET_PAY;
    REQUIRED PTR(expr);
    REQUIRED VAL(expr);
    GEN DO;
        'la      r2,{PTR}';
        'la      r0,{VAL}';
        'sw      r0,3(r2)';
    END;
END;

/* --- Descriptor construction macros ---
 *
 * ?BUILD_DESC: build a full descriptor at a pointer
 *   Input:  PTR(expr) -- destination pointer
 *           TAG(expr) -- tag byte
 *           SUB(expr) -- subtype byte
 *           PAY(expr) -- payload (24-bit)
 *   Clobbers: r0, r1, r2
 */

MACRODEF BUILD_DESC;
    REQUIRED PTR(expr);
    REQUIRED TAG(expr);
    REQUIRED SUB(expr);
    REQUIRED PAY(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lc      r0,{TAG}';
        'sb      r0,0(r2)';
        'lc      r0,{SUB}';
        'sb      r0,1(r2)';
        'lc      r0,0';
        'sb      r0,2(r2)';
        'la      r0,{PAY}';
        'sw      r0,3(r2)';
    END;
END;

/* ?BUILD_NULL: build a null descriptor
 *   Input:  PTR(expr) -- destination pointer
 *   Clobbers: r0, r2
 */

MACRODEF BUILD_NULL;
    REQUIRED PTR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lc      r0,0';
        'sb      r0,0(r2)';
        'sb      r0,1(r2)';
        'sb      r0,2(r2)';
        'sw      r0,3(r2)';
    END;
END;

/* ?BUILD_INT: build an integer descriptor
 *   Input:  PTR(expr) -- destination pointer
 *           VAL(expr) -- integer value (24-bit)
 *   Clobbers: r0, r2
 */

MACRODEF BUILD_INT;
    REQUIRED PTR(expr);
    REQUIRED VAL(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lc      r0,2';
        'sb      r0,0(r2)';
        'lc      r0,0';
        'sb      r0,1(r2)';
        'sb      r0,2(r2)';
        'la      r0,{VAL}';
        'sw      r0,3(r2)';
    END;
END;

/* ?BUILD_STR_REF: build a string reference descriptor
 *   Input:  PTR(expr) -- destination pointer
 *           ADDR(expr) -- pointer to heap string object
 *   Clobbers: r0, r2
 */

MACRODEF BUILD_STR_REF;
    REQUIRED PTR(expr);
    REQUIRED ADDR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lc      r0,3';
        'sb      r0,0(r2)';
        'lc      r0,0';
        'sb      r0,1(r2)';
        'sb      r0,2(r2)';
        'la      r0,{ADDR}';
        'sw      r0,3(r2)';
    END;
END;

/* ?BUILD_LABEL: build a label descriptor
 *   Input:  PTR(expr) -- destination pointer
 *           ID(expr)  -- label id or address
 *   Clobbers: r0, r2
 */

MACRODEF BUILD_LABEL;
    REQUIRED PTR(expr);
    REQUIRED ID(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lc      r0,6';
        'sb      r0,0(r2)';
        'lc      r0,0';
        'sb      r0,1(r2)';
        'sb      r0,2(r2)';
        'la      r0,{ID}';
        'sw      r0,3(r2)';
    END;
END;

/* --- Descriptor copy macro ---
 *
 * ?DESC_COPY: copy 6 bytes from SRC to DST
 *   Input:  DST(expr) -- destination pointer
 *           SRC(expr) -- source pointer
 *   Clobbers: r0, r1, r2
 */

MACRODEF DESC_COPY;
    REQUIRED DST(expr);
    REQUIRED SRC(expr);
    GEN DO;
        'la      r1,{SRC}';
        'la      r2,{DST}';
        'lb      r0,0(r1)';
        'sb      r0,0(r2)';
        'lb      r0,1(r1)';
        'sb      r0,1(r2)';
        'lb      r0,2(r1)';
        'sb      r0,2(r2)';
        'lw      r0,3(r1)';
        'sw      r0,3(r2)';
    END;
END;

/* --- Descriptor tag test macros ---
 *
 * ?DESC_IS_NULL: test if descriptor tag is null
 *   Input:  PTR(expr) -- pointer to descriptor
 *   Output: r0 = tag value (test with beqz/bnez after)
 *   Clobbers: r0, r2
 *
 * All IS_ macros load the tag into r0 for comparison.
 * Caller uses beqz/bnez or compares r0 to expected tag.
 */

MACRODEF DESC_IS_NULL;
    REQUIRED PTR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lb      r0,0(r2)';
    END;
END;

MACRODEF DESC_IS_INT;
    REQUIRED PTR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lb      r0,0(r2)';
    END;
END;

MACRODEF DESC_IS_STR;
    REQUIRED PTR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lb      r0,0(r2)';
    END;
END;

