/* test_descr.plsw -- Smoke test for descriptor and heap header layouts
 *
 * Exercises:
 *   - Descriptor construction (null, integer, string ref, label)
 *   - Descriptor field access
 *   - Descriptor copy
 *   - Heap object header construction
 *   - Header field access
 *   - Trace mask setup
 *
 * Output: prints test results via UART.
 * This is a build-validation program for Milestone 0, Step 1.
 */

%INCLUDE descr;
%INCLUDE heap;
%INCLUDE trace;

/* --- Global trace mask --- */
DCL TRACE_MASK INT INIT(0);

/* --- Scratch descriptors --- */
DCL D1(6) BYTE;
DCL D2(6) BYTE;
DCL D3(6) BYTE;

/* --- Scratch heap area (simulates heap region) --- */
DCL FAKE_HEAP(64) BYTE;

/* --- Output messages --- */
DCL MSG_PASS(8) CHAR INIT('PASS: ');
DCL MSG_FAIL(8) CHAR INIT('FAIL: ');
DCL MSG_NL(4) CHAR INIT('
');
DCL MSG_NULL(16) CHAR INIT('null desc');
DCL MSG_INT(16) CHAR INIT('int desc');
DCL MSG_COPY(16) CHAR INIT('desc copy');
DCL MSG_HDR(16) CHAR INIT('heap header');
DCL MSG_MARK(16) CHAR INIT('gc mark');
DCL MSG_DONE(16) CHAR INIT('All tests done');

/* --- Test counter --- */
DCL TESTS_RUN INT INIT(0);
DCL TESTS_PASS INT INIT(0);

/* --- Hex digit table --- */
DCL HEXCHARS(16) CHAR INIT('0123456789ABCDEF');

/* ============================================================
 * HEX24_PRINT: print a 24-bit value as 6 hex digits
 * ============================================================ */
HEX24_PRINT: PROC(VAL INT);
    DCL DIGIT INT;
    DCL SHIFT INT;
    DCL I INT;
    DCL V INT;

    V = VAL;
    /* Print 6 hex digits, high nibble first */
    DO I = 0 TO 5;
        /* Extract top nibble: shift right by (20 - I*4) */
        SHIFT = 20 - I * 4;
        IF (SHIFT > 0) THEN
            DIGIT = (V >> SHIFT) & 15;
        ELSE
            DIGIT = V & 15;
        CALL UART_PUTCHAR(HEXCHARS(DIGIT));
    END;
END;

/* ============================================================
 * REPORT: print PASS or FAIL with a label
 * ============================================================ */
REPORT: PROC(OK INT, LABEL PTR);
    TESTS_RUN = TESTS_RUN + 1;
    IF (OK != 0) THEN DO;
        CALL UART_PUTS(ADDR(MSG_PASS));
        TESTS_PASS = TESTS_PASS + 1;
    END;
    ELSE DO;
        CALL UART_PUTS(ADDR(MSG_FAIL));
    END;
    CALL UART_PUTS(LABEL);
    CALL UART_PUTS(ADDR(MSG_NL));
END;

/* ============================================================
 * MAIN
 * ============================================================ */
MAIN: PROC;
    DCL DPTR PTR;
    DCL HPTR PTR;
    DCL TAG_VAL INT;
    DCL PAY_VAL INT;
    DCL KIND_VAL INT;
    DCL SIZE_VAL INT;
    DCL FLAGS_VAL INT;
    DCL OK INT;

    /* Enable all tracing for this test */
    TRACE_MASK = TR_ALL;

    /* ---- Test 1: Build null descriptor ---- */
    DPTR = ADDR(D1);
    ?BUILD_NULL(PTR(DPTR));

    /* Read back tag -- should be TAG_NULL (0) */
    TAG_VAL = DPTR->DTAG;
    PAY_VAL = DPTR->DPAY;
    OK = (TAG_VAL = TAG_NULL) AND (PAY_VAL = 0);
    CALL REPORT(OK, ADDR(MSG_NULL));

    /* ---- Test 2: Build integer descriptor ---- */
    DPTR = ADDR(D2);
    ?BUILD_INT(PTR(DPTR), VAL(42));

    TAG_VAL = DPTR->DTAG;
    PAY_VAL = DPTR->DPAY;
    OK = (TAG_VAL = TAG_INT) AND (PAY_VAL = 42);
    CALL REPORT(OK, ADDR(MSG_INT));

    /* ---- Test 3: Copy descriptor ---- */
    ?DESC_COPY(DST(ADDR(D3)), SRC(ADDR(D2)));

    DPTR = ADDR(D3);
    TAG_VAL = DPTR->DTAG;
    PAY_VAL = DPTR->DPAY;
    OK = (TAG_VAL = TAG_INT) AND (PAY_VAL = 42);
    CALL REPORT(OK, ADDR(MSG_COPY));

    /* ---- Test 4: Build heap object header ---- */
    HPTR = ADDR(FAKE_HEAP);
    ?BUILD_HDR(PTR(HPTR), KIND(OBK_STRING), SIZE(24));

    KIND_VAL = HPTR->OKIND;
    SIZE_VAL = HPTR->OSIZE;
    OK = (KIND_VAL = OBK_STRING) AND (SIZE_VAL = 24);
    CALL REPORT(OK, ADDR(MSG_HDR));

    /* ---- Test 5: GC mark set/check ---- */
    HPTR = ADDR(FAKE_HEAP);
    ?OBJ_SET_MARK(PTR(HPTR));
    FLAGS_VAL = HPTR->OFLAGS;
    OK = (FLAGS_VAL & OBF_MARK) != 0;
    CALL REPORT(OK, ADDR(MSG_MARK));

    /* ---- Summary ---- */
    CALL UART_PUTS(ADDR(MSG_DONE));
    CALL UART_PUTS(ADDR(MSG_NL));
END;

