1	/* descr.msw -- SNOBOL4 Descriptor Layout for COR24
2	 *
3	 * A descriptor is a 2-word (6-byte) tagged value.
4	 *
5	 * Word 0 (3 bytes):
6	 *   byte 0: primary tag     (DESC_TAG)
7	 *   byte 1: subtype/flags   (DESC_SUB)
8	 *   byte 2: reserved        (DESC_RSV)
9	 *
10	 * Word 1 (3 bytes):
11	 *   bytes 3-5: payload      (DESC_PAY) -- integer, pointer, or id
12	 *
13	 * Descriptors are always copied and compared as 6-byte units.
14	 * Physical layout is COR24-specific; semantic meaning is portable.
15	 */
16	
17	/* --- Tag constants (byte 0) --- */
18	
19	%DEFINE TAG_NULL     0;
20	%DEFINE TAG_UNINIT   1;
21	%DEFINE TAG_INT      2;
22	%DEFINE TAG_STR      3;
23	%DEFINE TAG_SYM      4;
24	%DEFINE TAG_PAT      5;
25	%DEFINE TAG_LABEL    6;
26	%DEFINE TAG_BUILTIN  7;
27	%DEFINE TAG_REAL     8;
28	%DEFINE TAG_ARRAY    9;
29	%DEFINE TAG_TABLE    10;
30	%DEFINE TAG_COUNT    11;
31	
32	/* --- Subtype / flag bits (byte 1) --- */
33	/* Low nibble: subtype (type-specific)
34	 * High nibble: flags
35	 *   bit 7: GC-forwarded
36	 *   bit 6: immutable
37	 *   bit 5: reserved
38	 *   bit 4: reserved
39	 */
40	
41	%DEFINE DFLAG_FWD    128;
42	%DEFINE DFLAG_IMMUT  64;
43	
44	/* --- Descriptor size --- */
45	
46	%DEFINE DESC_BYTES   6;
47	%DEFINE DESC_WORDS   2;
48	
49	/* --- Descriptor as BASED record --- */
50	
51	DCL 1 DESCR BASED,
52	    3 DTAG   BYTE,
53	    3 DSUB   BYTE,
54	    3 DRSV   BYTE,
55	    3 DPAY   PTR;
56	
57	/* --- Descriptor access macros ---
58	 *
59	 * These macros operate on a descriptor through a pointer.
60	 *
61	 * ?DESC_TAG: read tag byte from descriptor at pointer
62	 *   Input:  PTR(expr) -- pointer to descriptor
63	 *   Output: inline asm loads tag into r0
64	 *   Clobbers: r0, r2
65	 *
66	 * ?DESC_SET_TAG: write tag byte
67	 *   Input:  PTR(expr) -- pointer to descriptor
68	 *           VAL(expr) -- tag value
69	 *   Clobbers: r0, r1, r2
70	 */
71	
72	MACRODEF DESC_TAG;
73	    REQUIRED PTR(expr);
74	    GEN DO;
75	        'la      r2,{PTR}';
76	        'lb      r0,0(r2)';
77	    END;
78	END;
79	
80	MACRODEF DESC_SET_TAG;
81	    REQUIRED PTR(expr);
82	    REQUIRED VAL(expr);
83	    GEN DO;
84	        'la      r2,{PTR}';
85	        'lc      r0,{VAL}';
86	        'sb      r0,0(r2)';
87	    END;
88	END;
89	
90	MACRODEF DESC_SUB;
91	    REQUIRED PTR(expr);
92	    GEN DO;
93	        'la      r2,{PTR}';
94	        'lb      r0,1(r2)';
95	    END;
96	END;
97	
98	MACRODEF DESC_SET_SUB;
99	    REQUIRED PTR(expr);
100	    REQUIRED VAL(expr);
101	    GEN DO;
102	        'la      r2,{PTR}';
103	        'lc      r0,{VAL}';
104	        'sb      r0,1(r2)';
105	    END;
106	END;
107	
108	MACRODEF DESC_PAY;
109	    REQUIRED PTR(expr);
110	    GEN DO;
111	        'la      r2,{PTR}';
112	        'lw      r0,3(r2)';
113	    END;
114	END;
115	
116	MACRODEF DESC_SET_PAY;
117	    REQUIRED PTR(expr);
118	    REQUIRED VAL(expr);
119	    GEN DO;
120	        'la      r2,{PTR}';
121	        'la      r0,{VAL}';
122	        'sw      r0,3(r2)';
123	    END;
124	END;
125	
126	/* --- Descriptor construction macros ---
127	 *
128	 * ?BUILD_DESC: build a full descriptor at a pointer
129	 *   Input:  PTR(expr) -- destination pointer
130	 *           TAG(expr) -- tag byte
131	 *           SUB(expr) -- subtype byte
132	 *           PAY(expr) -- payload (24-bit)
133	 *   Clobbers: r0, r1, r2
134	 */
135	
136	MACRODEF BUILD_DESC;
137	    REQUIRED PTR(expr);
138	    REQUIRED TAG(expr);
139	    REQUIRED SUB(expr);
140	    REQUIRED PAY(expr);
141	    GEN DO;
142	        'la      r2,{PTR}';
143	        'lc      r0,{TAG}';
144	        'sb      r0,0(r2)';
145	        'lc      r0,{SUB}';
146	        'sb      r0,1(r2)';
147	        'lc      r0,0';
148	        'sb      r0,2(r2)';
149	        'la      r0,{PAY}';
150	        'sw      r0,3(r2)';
151	    END;
152	END;
153	
154	/* ?BUILD_NULL: build a null descriptor
155	 *   Input:  PTR(expr) -- destination pointer
156	 *   Clobbers: r0, r2
157	 */
158	
159	MACRODEF BUILD_NULL;
160	    REQUIRED PTR(expr);
161	    GEN DO;
162	        'la      r2,{PTR}';
163	        'lc      r0,0';
164	        'sb      r0,0(r2)';
165	        'sb      r0,1(r2)';
166	        'sb      r0,2(r2)';
167	        'sw      r0,3(r2)';
168	    END;
169	END;
170	
171	/* ?BUILD_INT: build an integer descriptor
172	 *   Input:  PTR(expr) -- destination pointer
173	 *           VAL(expr) -- integer value (24-bit)
174	 *   Clobbers: r0, r2
175	 */
176	
177	MACRODEF BUILD_INT;
178	    REQUIRED PTR(expr);
179	    REQUIRED VAL(expr);
180	    GEN DO;
181	        'la      r2,{PTR}';
182	        'lc      r0,2';
183	        'sb      r0,0(r2)';
184	        'lc      r0,0';
185	        'sb      r0,1(r2)';
186	        'sb      r0,2(r2)';
187	        'la      r0,{VAL}';
188	        'sw      r0,3(r2)';
189	    END;
190	END;
191	
192	/* ?BUILD_STR_REF: build a string reference descriptor
193	 *   Input:  PTR(expr) -- destination pointer
194	 *           ADDR(expr) -- pointer to heap string object
195	 *   Clobbers: r0, r2
196	 */
197	
198	MACRODEF BUILD_STR_REF;
199	    REQUIRED PTR(expr);
200	    REQUIRED ADDR(expr);
201	    GEN DO;
202	        'la      r2,{PTR}';
203	        'lc      r0,3';
204	        'sb      r0,0(r2)';
205	        'lc      r0,0';
206	        'sb      r0,1(r2)';
207	        'sb      r0,2(r2)';
208	        'la      r0,{ADDR}';
209	        'sw      r0,3(r2)';
210	    END;
211	END;
212	
213	/* ?BUILD_LABEL: build a label descriptor
214	 *   Input:  PTR(expr) -- destination pointer
215	 *           ID(expr)  -- label id or address
216	 *   Clobbers: r0, r2
217	 */
218	
219	MACRODEF BUILD_LABEL;
220	    REQUIRED PTR(expr);
221	    REQUIRED ID(expr);
222	    GEN DO;
223	        'la      r2,{PTR}';
224	        'lc      r0,6';
225	        'sb      r0,0(r2)';
226	        'lc      r0,0';
227	        'sb      r0,1(r2)';
228	        'sb      r0,2(r2)';
229	        'la      r0,{ID}';
230	        'sw      r0,3(r2)';
231	    END;
232	END;
233	
234	/* --- Descriptor copy macro ---
235	 *
236	 * ?DESC_COPY: copy 6 bytes from SRC to DST
237	 *   Input:  DST(expr) -- destination pointer
238	 *           SRC(expr) -- source pointer
239	 *   Clobbers: r0, r1, r2
240	 */
241	
242	MACRODEF DESC_COPY;
243	    REQUIRED DST(expr);
244	    REQUIRED SRC(expr);
245	    GEN DO;
246	        'la      r1,{SRC}';
247	        'la      r2,{DST}';
248	        'lb      r0,0(r1)';
249	        'sb      r0,0(r2)';
250	        'lb      r0,1(r1)';
251	        'sb      r0,1(r2)';
252	        'lb      r0,2(r1)';
253	        'sb      r0,2(r2)';
254	        'lw      r0,3(r1)';
255	        'sw      r0,3(r2)';
256	    END;
257	END;
258	
259	/* --- Descriptor tag test macros ---
260	 *
261	 * ?DESC_IS_NULL: test if descriptor tag is null
262	 *   Input:  PTR(expr) -- pointer to descriptor
263	 *   Output: r0 = tag value (test with beqz/bnez after)
264	 *   Clobbers: r0, r2
265	 *
266	 * All IS_ macros load the tag into r0 for comparison.
267	 * Caller uses beqz/bnez or compares r0 to expected tag.
268	 */
269	
270	MACRODEF DESC_IS_NULL;
271	    REQUIRED PTR(expr);
272	    GEN DO;
273	        'la      r2,{PTR}';
274	        'lb      r0,0(r2)';
275	    END;
276	END;
277	
278	MACRODEF DESC_IS_INT;
279	    REQUIRED PTR(expr);
280	    GEN DO;
281	        'la      r2,{PTR}';
282	        'lb      r0,0(r2)';
283	    END;
284	END;
285	
286	MACRODEF DESC_IS_STR;
287	    REQUIRED PTR(expr);
288	    GEN DO;
289	        'la      r2,{PTR}';
290	        'lb      r0,0(r2)';
291	    END;
292	END;
293

