/* trace.msw -- SNOBOL4 Assertion, Tracing, and Logging for COR24
 *
 * Provides compile-time trace category flags and runtime macros
 * for conditional tracing and assertion checking.
 *
 * Trace output goes to UART via UART_PUTS / UART_PUTCHAR.
 * Assert failures halt execution via trap instruction.
 */

/* --- Trace category bit flags --- */
/* These are ORed together into a global trace mask.
 * Each category can be enabled/disabled independently.
 */

%DEFINE TR_NONE      0;
%DEFINE TR_ALLOC     1;
%DEFINE TR_STMT      2;
%DEFINE TR_EXPR      4;
%DEFINE TR_PATTERN   8;
%DEFINE TR_GC        16;
%DEFINE TR_BTRAK     32;
%DEFINE TR_DUMP      64;
%DEFINE TR_ALL       127;

/* --- Assert macro ---
 *
 * ?SNO_ASSERT: check condition, trap if zero
 *   Input:  COND(expr) -- value to test (0 = failure)
 *   Effect: if COND is zero, executes trap instruction (halts CPU)
 *   Clobbers: r0
 *
 * The trap instruction stops the COR24 emulator and produces
 * a diagnostic dump. Use for invariant checks during development.
 */

MACRODEF SNO_ASSERT;
    REQUIRED COND(expr);
    GEN DO;
        'la      r0,{COND}';
        'bnez    r0,_sa_ok_{COND}';
        'trap';
        '_sa_ok_{COND}:';
    END;
END;

/* --- Trace test macro ---
 *
 * ?TR_TEST: test if a trace category is enabled
 *   Input:  MASK(expr) -- address of global trace mask variable
 *           CAT(expr)  -- category bit to test
 *   Output: r0 = nonzero if category enabled
 *   Clobbers: r0, r2
 *
 * Typical usage:
 *   ?TR_TEST(MASK(ADDR(TRACE_MASK)), CAT(1));
 *   -- then branch on r0 to skip or emit trace
 */

MACRODEF TR_TEST;
    REQUIRED MASK(expr);
    REQUIRED CAT(expr);
    GEN DO;
        'la      r2,{MASK}';
        'lw      r0,0(r2)';
        'and     r0,{CAT}';
    END;
END;

/* --- Trace emit macro ---
 *
 * ?TR_PUTS: emit a trace string if category is enabled
 *   Input:  MASK(expr) -- address of global trace mask variable
 *           CAT(expr)  -- category bit to test
 *           MSG(expr)  -- address of null-terminated string
 *   Clobbers: r0, r1, r2
 *
 * Checks the trace mask first; skips output if category disabled.
 */

MACRODEF TR_PUTS;
    REQUIRED MASK(expr);
    REQUIRED CAT(expr);
    REQUIRED MSG(expr);
    GEN DO;
        'la      r2,{MASK}';
        'lw      r0,0(r2)';
        'and     r0,{CAT}';
        'beqz    r0,_tr_skip_{MSG}';
        'la      r0,{MSG}';
        'push    r0';
        'la      r2,_UART_PUTS';
        'jal     r1,(r2)';
        'add     sp,3';
        '_tr_skip_{MSG}:';
    END;
END;

/* --- Trap macro ---
 *
 * ?SNO_TRAP: unconditional trap (halt with diagnostic dump)
 *   Clobbers: none
 */

MACRODEF SNO_TRAP;
    GEN DO;
        'trap';
    END;
END;

/* --- Hex print helper ---
 *
 * ?TR_HEX24: print a 24-bit value as 6 hex digits via UART
 *   Input:  VAL(expr) -- 24-bit value to print
 *   Clobbers: r0, r1, r2
 *
 * Useful for diagnostic dumps of pointers and sizes.
 * Assumes a HEX24_PRINT procedure exists in the runtime.
 */

MACRODEF TR_HEX24;
    REQUIRED VAL(expr);
    GEN DO;
        'la      r0,{VAL}';
        'push    r0';
        'la      r2,_HEX24_PRINT';
        'jal     r1,(r2)';
        'add     sp,3';
    END;
END;

