        'lc r0,0'; 'sb r0,1(r2)'; 'sb r0,2(r2)';
        'la r0,{SIZE}'; 'sw r0,3(r2)';
    END;
END;

/* GC mark macros. Clobbers r0,r1,r2 */
MACRODEF OBJ_SET_MARK;
    REQUIRED PTR(expr);
    GEN DO;
        'la r2,{PTR}'; 'lb r0,1(r2)';
        'lc r1,128'; 'or r0,r1';
        'sb r0,1(r2)';
    END;
END;
