DESC_CPY: PROC(D PTR, S PTR);
    DCL DP PTR;
    DCL SP PTR;
    DP = D;
    SP = S;
    DP->DTAG = SP->DTAG;
    DP->DSUB = SP->DSUB;
    DP->DRSV = SP->DRSV;
    DP->DPAY = SP->DPAY;
END;

/* --- Helper: init heap header --- */
HDR_INIT: PROC(P PTR, K BYTE, SZ INT);
    DCL HP PTR;
    HP = P;
    HP->OKIND = K;
    HP->OFLAGS = 0;
    HP->ORSV = 0;
    HP->OSIZE = SZ;
END;

