/* test_snolib.plsw -- Test descriptor helpers and runtime library
 *
 * Tests: DESC_SET_*, DESC_IS_*, DESC_CELL_CPY, DESC_EQ,
 *        DESC_TAG_GET, DESC_PAY_GET, TAG_NAME, KIND_NAME,
 *        HDR_SET, HDR_IS_FREE, HDR_PAYLOAD, HDR_NEXT,
 *        PUT_HEX_BYTE, PUT_HEX24, GC mark with OBF_MARK=128
 */

%INCLUDE descr;
%INCLUDE heap;
%INCLUDE trace;

/* ---- snolib procs (included directly) ---- */

/* DESC_SET: initialize a descriptor at pointer P */
DESC_SET: PROC(P PTR, T BYTE, S BYTE, V INT);
    DCL DP PTR;
    DP = P;
    DP->DTAG = T;
    DP->DSUB = S;
    DP->DRSV = 0;
    DP->DPAY = V;
END;

DESC_SET_NULL: PROC(P PTR);
    DCL DP PTR;
    DP = P;
    DP->DTAG = TAG_NULL;
    DP->DSUB = 0;
    DP->DRSV = 0;
    DP->DPAY = 0;
END;

DESC_SET_INT: PROC(P PTR, V INT);
    DCL DP PTR;
    DP = P;
    DP->DTAG = TAG_INT;
    DP->DSUB = 0;
    DP->DRSV = 0;
    DP->DPAY = V;
END;

DESC_SET_STR: PROC(P PTR, SPTR PTR);
    DCL DP PTR;
    DP = P;
    DP->DTAG = TAG_STR;
    DP->DSUB = 0;
    DP->DRSV = 0;
    DP->DPAY = SPTR;
END;

DESC_CELL_CPY: PROC(DST PTR, SRC PTR);
    DCL DP PTR;
    DCL SP PTR;
    DP = DST;
    SP = SRC;
    DP->DTAG = SP->DTAG;
    DP->DSUB = SP->DSUB;
    DP->DRSV = SP->DRSV;
    DP->DPAY = SP->DPAY;
END;

DESC_IS_NULL: PROC(P PTR) RETURNS(INT);
    DCL DP PTR;
    DP = P;
    IF (DP->DTAG = TAG_NULL) THEN RETURN(1);
    RETURN(0);
END;

DESC_IS_INT: PROC(P PTR) RETURNS(INT);
    DCL DP PTR;
    DP = P;
    IF (DP->DTAG = TAG_INT) THEN RETURN(1);
    RETURN(0);
END;

DESC_TAG_GET: PROC(P PTR) RETURNS(INT);
    DCL DP PTR;
    DP = P;
    RETURN(DP->DTAG);
END;

DESC_PAY_GET: PROC(P PTR) RETURNS(INT);
    DCL DP PTR;
    DP = P;
    RETURN(DP->DPAY);
END;

DESC_EQ: PROC(A PTR, B PTR) RETURNS(INT);
    DCL AP PTR;
    DCL BP PTR;
    AP = A;
    BP = B;
    IF (AP->DTAG = BP->DTAG) THEN
        IF (AP->DPAY = BP->DPAY) THEN
            RETURN(1);
    RETURN(0);
END;

HDR_SET: PROC(P PTR, K BYTE, SZ INT);
    DCL HP PTR;
    HP = P;
    HP->OKIND = K;
    HP->OFLAGS = 0;
    HP->ORSV = 0;
    HP->OSIZE = SZ;
END;

HDR_IS_FREE: PROC(P PTR) RETURNS(INT);
    DCL HP PTR;
    HP = P;
    IF (HP->OKIND = OBK_FREE) THEN RETURN(1);
    RETURN(0);
END;

HDR_PAYLOAD: PROC(P PTR) RETURNS(INT);
    RETURN(P + HDR_BYTES);
END;

HDR_NEXT: PROC(P PTR) RETURNS(INT);
    DCL HP PTR;
    HP = P;
    RETURN(P + HP->OSIZE);
END;

DCL TN_NULL(8) CHAR INIT('null');
DCL TN_INT(8) CHAR INIT('int');
DCL TN_STR(8) CHAR INIT('str');
DCL TN_UNK(8) CHAR INIT('???');

TAG_NAME: PROC(T INT) RETURNS(INT);
    IF (T = TAG_NULL) THEN RETURN(ADDR(TN_NULL));
    IF (T = TAG_INT) THEN RETURN(ADDR(TN_INT));
    IF (T = TAG_STR) THEN RETURN(ADDR(TN_STR));
    RETURN(ADDR(TN_UNK));
END;

DCL KN_FREE(8) CHAR INIT('free');
DCL KN_STRING(8) CHAR INIT('string');
DCL KN_UNK(8) CHAR INIT('???');

KIND_NAME: PROC(K INT) RETURNS(INT);
    IF (K = OBK_FREE) THEN RETURN(ADDR(KN_FREE));
    IF (K = OBK_STRING) THEN RETURN(ADDR(KN_STRING));
    RETURN(ADDR(KN_UNK));
END;

DCL HEXCHARS(16) CHAR INIT('0123456789ABCDEF');

PUT_HEX_BYTE: PROC(V INT);
    DCL HI INT;
    DCL LO INT;
    HI = V;
    LO = 0;
    DO WHILE (HI > 15);
        HI = HI - 16;
        LO = LO + 1;
    END;
    CALL UART_PUTCHAR(HEXCHARS(LO));
    CALL UART_PUTCHAR(HEXCHARS(HI));
END;

PUT_HEX24: PROC(V INT);
    DCL B2 INT;
