DCL T02(16) CHAR INIT('02 set_int');
DCL T03(16) CHAR INIT('03 cell_cpy');
DCL T04(16) CHAR INIT('04 is_null');
DCL T05(16) CHAR INIT('05 is_int');
DCL T06(16) CHAR INIT('06 tag_get');
DCL T07(16) CHAR INIT('07 pay_get');
DCL T08(16) CHAR INIT('08 desc_eq');
DCL T09(16) CHAR INIT('09 desc_neq');
DCL T10(16) CHAR INIT('10 hdr_set');
DCL T11(16) CHAR INIT('11 hdr_free');
DCL T12(16) CHAR INIT('12 hdr_pay');
DCL T13(16) CHAR INIT('13 hdr_next');
DCL T14(16) CHAR INIT('14 hex24');
DCL T15(16) CHAR INIT('15 gc_mark');
DCL T16(16) CHAR INIT('16 tag_name');
DCL M_DONE(20) CHAR INIT('All tests done');

CHK: PROC(OK INT, MSG PTR);
    IF (OK != 0) THEN
