    ELSE
        CALL UART_PUTS(ADDR(M_F));
    CALL UART_PUTS(MSG);
    CALL UART_PUTS(ADDR(M_NL));
END;

/* ---- Main ---- */

MAIN: PROC;
    DCL DP PTR;
    DCL HP PTR;
    DCL OK INT;
    DCL V INT;
    DCL NP PTR;

    /* 01 set_null */
    CALL DESC_SET_NULL(ADDR(D1));
    DP = ADDR(D1);
    OK = (DP->DTAG = TAG_NULL) AND (DP->DPAY = 0);
    CALL CHK(OK, ADDR(T01));

    /* 02 set_int */
    CALL DESC_SET_INT(ADDR(D1), 99);
    DP = ADDR(D1);
    OK = (DP->DTAG = TAG_INT) AND (DP->DPAY = 99);
    CALL CHK(OK, ADDR(T02));

    /* 03 cell_cpy */
    CALL DESC_SET_INT(ADDR(D2), 77);
    CALL DESC_CELL_CPY(ADDR(D3), ADDR(D2));
    DP = ADDR(D3);
    OK = (DP->DTAG = TAG_INT) AND (DP->DPAY = 77);
    CALL CHK(OK, ADDR(T03));

    /* 04 is_null */
    CALL DESC_SET_NULL(ADDR(D1));
    OK = DESC_IS_NULL(ADDR(D1));
    CALL CHK(OK, ADDR(T04));

    /* 05 is_int */
    CALL DESC_SET_INT(ADDR(D1), 5);
    OK = DESC_IS_INT(ADDR(D1));
    CALL CHK(OK, ADDR(T05));

    /* 06 tag_get */
    V = DESC_TAG_GET(ADDR(D1));
    OK = (V = TAG_INT);
    CALL CHK(OK, ADDR(T06));

    /* 07 pay_get */
    V = DESC_PAY_GET(ADDR(D1));
    OK = (V = 5);
    CALL CHK(OK, ADDR(T07));

    /* 08 desc_eq */
    CALL DESC_SET_INT(ADDR(D1), 42);
    CALL DESC_SET_INT(ADDR(D2), 42);
    OK = DESC_EQ(ADDR(D1), ADDR(D2));
    CALL CHK(OK, ADDR(T08));

    /* 09 desc_neq */
    CALL DESC_SET_INT(ADDR(D2), 43);
    V = DESC_EQ(ADDR(D1), ADDR(D2));
    OK = (V = 0);
    CALL CHK(OK, ADDR(T09));

    /* 10 hdr_set */
    CALL HDR_SET(ADDR(HEAP1), OBK_STRING, 24);
    HP = ADDR(HEAP1);
    OK = (HP->OKIND = OBK_STRING) AND (HP->OSIZE = 24);
    CALL CHK(OK, ADDR(T10));

    /* 11 hdr_free */
    CALL HDR_SET(ADDR(HEAP1), OBK_FREE, 12);
    OK = HDR_IS_FREE(ADDR(HEAP1));
    CALL CHK(OK, ADDR(T11));

    /* 12 hdr_payload */
    V = HDR_PAYLOAD(ADDR(HEAP1));
    OK = (V = ADDR(HEAP1) + 6);
    CALL CHK(OK, ADDR(T12));

    /* 13 hdr_next */
    CALL HDR_SET(ADDR(HEAP1), OBK_STRING, 20);
    NP = HDR_NEXT(ADDR(HEAP1));
    OK = (NP = ADDR(HEAP1) + 20);
    CALL CHK(OK, ADDR(T13));

    /* 14 hex24 (visual: expect 00002A) */
    CALL UART_PUTS(ADDR(M_P));
    CALL UART_PUTS(ADDR(T14));
    CALL UART_PUTCHAR(32);
    CALL PUT_HEX24(42);
    CALL UART_PUTS(ADDR(M_NL));

    /* 15 gc_mark (OBF_MARK=128) */
    CALL HDR_SET(ADDR(HEAP1), OBK_STRING, 24);
    HP = ADDR(HEAP1);
    HP->OFLAGS = OBF_MARK;
    OK = (HP->OFLAGS = OBF_MARK);
    CALL CHK(OK, ADDR(T15));

    /* 16 tag_name */
    NP = TAG_NAME(TAG_INT);
    OK = (NP = ADDR(TN_INT));
    CALL CHK(OK, ADDR(T16));

    CALL UART_PUTS(ADDR(M_DONE));
    CALL UART_PUTS(ADDR(M_NL));
END;

