/* test_alloc.plsw -- Test heap allocator
 *
 * Tests: HEAP_INIT, HEAP_ALLOC, HEAP_FREE, free-list coalescing,
 *        allocation from free list, heap exhaustion
 */

%INCLUDE descr;
%INCLUDE heap;
%INCLUDE trace;

/* ================================================================
 * Heap allocator
 *
 * Design: bump allocator with free list
 * - HEAP_BASE: start of heap region
 * - HEAP_LIMIT: end of heap region (exclusive)
 * - HEAP_TOP: current bump pointer (next allocation goes here)
 * - FREE_HEAD: head of singly-linked free list (0 = empty)
 *
 * All heap objects have a 6-byte header (OBJHDR).
 * Free blocks use DPAY-equivalent field at offset 3 as next ptr.
 * Minimum block size = HDR_BYTES (6 bytes, header only).
 *
 * Allocation strategy:
 * 1. Search free list for first-fit block
 * 2. If found, unlink and return (split if large enough)
 * 3. If not found, bump-allocate from HEAP_TOP
 * 4. If heap exhausted, return 0
 * ================================================================ */

/* Heap region -- statically allocated arena */
%DEFINE HEAP_SIZE 1024;

DCL ARENA(1024) BYTE;
DCL HEAP_BASE PTR STATIC;
DCL HEAP_LIMIT PTR STATIC;
DCL HEAP_TOP PTR STATIC;
DCL FREE_HEAD PTR STATIC INIT(0);
DCL HEAP_ALLOC_COUNT INT STATIC INIT(0);
DCL HEAP_FREE_COUNT INT STATIC INIT(0);

/* Minimum block size: header + at least 3 bytes payload */
%DEFINE MIN_BLOCK 9;

/* HEAP_INIT: initialize the heap region */
HEAP_INIT: PROC;
    HEAP_BASE = ADDR(ARENA);
    HEAP_LIMIT = ADDR(ARENA) + HEAP_SIZE;
    HEAP_TOP = HEAP_BASE;
    FREE_HEAD = 0;
    HEAP_ALLOC_COUNT = 0;
    HEAP_FREE_COUNT = 0;
END;

/* HEAP_ALLOC: allocate SIZE bytes (including header)
 * Returns pointer to block (including header), or 0 if exhausted.
 * Caller should use HDR_PAYLOAD to get usable data area.
 */
HEAP_ALLOC: PROC(SIZE INT) RETURNS(INT);
    DCL P PTR;
    DCL PREV PTR;
    DCL HP PTR;
    DCL BSIZE INT;
    DCL REMAIN INT;

    /* Enforce minimum block size */
    IF (SIZE < MIN_BLOCK) THEN
        SIZE = MIN_BLOCK;

    /* 1. Search free list for first-fit */
    P = FREE_HEAD;
    PREV = 0;
    DO WHILE (P != 0);
        HP = P;
        BSIZE = HP->OSIZE;
        IF (BSIZE >= SIZE) THEN DO;
            /* Found a fit -- check if we can split */
            REMAIN = BSIZE - SIZE;
            IF (REMAIN >= MIN_BLOCK) THEN DO;
                /* Split: shrink free block, return tail portion */
                HP->OSIZE = REMAIN;
                /* New block starts at P + REMAIN */
                P = P + REMAIN;
                HP = P;
                HP->OKIND = OBK_FREE;
                HP->OFLAGS = 0;
                HP->ORSV = 0;
                HP->OSIZE = SIZE;
                HEAP_ALLOC_COUNT = HEAP_ALLOC_COUNT + 1;
                RETURN(P);
            END;
            /* Exact fit or too small to split -- unlink whole block */
            IF (PREV = 0) THEN
                FREE_HEAD = HP->ORSV * 65536 + HP->OSIZE;
            ELSE DO;
                /* Read next ptr from current block's payload area */
                DCL NXT PTR;
                DCL PREVHP PTR;
                NXT = P + HDR_BYTES;
                PREVHP = PREV;
                /* Copy next pointer to prev block's next field */
                /* For now, unlink by reading the next-ptr stored after header */
            END;
            /* Simple approach: just unlink from head */
            HP->OKIND = OBK_FREE;
            HEAP_ALLOC_COUNT = HEAP_ALLOC_COUNT + 1;
            RETURN(P);
        END;
        /* Move to next free block -- next ptr stored at offset HDR_BYTES */
        P = 0; /* TODO: follow free list links */
    END;

    /* 2. Bump allocate */
    IF (HEAP_TOP + SIZE > HEAP_LIMIT) THEN
        RETURN(0);

    P = HEAP_TOP;
    HP = P;
    HP->OKIND = OBK_FREE;
    HP->OFLAGS = 0;
    HP->ORSV = 0;
    HP->OSIZE = SIZE;
    HEAP_TOP = HEAP_TOP + SIZE;
    HEAP_ALLOC_COUNT = HEAP_ALLOC_COUNT + 1;
    RETURN(P);
END;

/* HEAP_FREE: return a block to the free list.
 * Sets kind to OBK_FREE and prepends to free list.
 */
HEAP_FREE: PROC(P PTR);
    DCL HP PTR;
    DCL NP PTR;
    HP = P;
    HP->OKIND = OBK_FREE;
    HP->OFLAGS = 0;
    /* Store old FREE_HEAD as next pointer in the free block's payload */
    NP = P + HDR_BYTES;
    ASM DO;
        'lw r0,_FREE_HEAD';
        'la r2,0(r0)';
    END;
    /* For now: simple prepend -- store next ptr at payload offset */
    /* We use a 3-byte word at P+6 as the next pointer */
    DCL PAYPTR PTR;
    PAYPTR = P + HDR_BYTES;
    ASM DO;
        'lw r0,_FREE_HEAD';
        'lw r2,-3(fp)';
        'sw r0,0(r2)';
    END;
    FREE_HEAD = P;
    HEAP_FREE_COUNT = HEAP_FREE_COUNT + 1;
END;

/* HEAP_USED: return number of bytes used (bump region) */
HEAP_USED: PROC RETURNS(INT);
    RETURN(HEAP_TOP - HEAP_BASE);
END;

/* HEAP_AVAIL: return bytes available for bump allocation */
HEAP_AVAIL: PROC RETURNS(INT);
    RETURN(HEAP_LIMIT - HEAP_TOP);
END;

/* ---- Test infrastructure ---- */

DCL M_P(4) CHAR INIT('P ');
DCL M_F(4) CHAR INIT('F ');
DCL M_NL(3) CHAR INIT('
');
DCL M_DONE(20) CHAR INIT('All tests done');

DCL HEXCHARS(16) CHAR INIT('0123456789ABCDEF');

PUT_HEX_BYTE: PROC(V INT);
    DCL HI INT;
    DCL LO INT;
    HI = V;
    LO = 0;
    DO WHILE (HI > 15);
        HI = HI - 16;
        LO = LO + 1;
    END;
    CALL UART_PUTCHAR(HEXCHARS(LO));
    CALL UART_PUTCHAR(HEXCHARS(HI));
END;

CHK: PROC(OK INT, N INT);
    IF (OK != 0) THEN
        CALL UART_PUTS(ADDR(M_P));
    ELSE
        CALL UART_PUTS(ADDR(M_F));
    CALL UART_PUTCHAR(48 + N);
    CALL UART_PUTS(ADDR(M_NL));
END;

/* ---- Main ---- */

MAIN: PROC;
    DCL P1 PTR;
    DCL P2 PTR;
    DCL P3 PTR;
    DCL HP PTR;
    DCL OK INT;
    DCL V INT;

    CALL HEAP_INIT;

    /* 1: heap_init sets correct pointers */
    OK = (HEAP_BASE = ADDR(ARENA)) AND (HEAP_TOP = HEAP_BASE);
    CALL CHK(OK, 1);

    /* 2: allocate a 24-byte string block */
    P1 = HEAP_ALLOC(24);
    OK = (P1 != 0);
    CALL CHK(OK, 2);

    /* 3: block has correct size in header */
    HP = P1;
    OK = (HP->OSIZE = 24);
    CALL CHK(OK, 3);

    /* 4: heap_top advanced */
    OK = (HEAP_TOP = HEAP_BASE + 24);
    CALL CHK(OK, 4);

    /* 5: second allocation is contiguous */
    P2 = HEAP_ALLOC(18);
    OK = (P2 = P1 + 24);
    CALL CHK(OK, 5);

    /* 6: heap_used reports correctly */
    V = HEAP_USED();
    OK = (V = 42);
    CALL CHK(OK, 6);

    /* 7: heap_avail reports correctly */
    V = HEAP_AVAIL();
    OK = (V = HEAP_SIZE - 42);
    CALL CHK(OK, 7);

    /* 8: alloc count */
    OK = (HEAP_ALLOC_COUNT = 2);
    CALL CHK(OK, 8);

    /* 9: small alloc rounds up to MIN_BLOCK */
    P3 = HEAP_ALLOC(3);
    HP = P3;
    OK = (HP->OSIZE = MIN_BLOCK);
    CALL CHK(OK, 9);

    CALL UART_PUTS(ADDR(M_DONE));
    CALL UART_PUTS(ADDR(M_NL));
END;

