    CALL HEAP_INIT;

    /* 1: heap_init sets correct pointers */
    OK = (HEAP_BASE = ADDR(ARENA)) AND (HEAP_TOP = HEAP_BASE);
    CALL CHK(OK, 1);

    /* 2: allocate 24-byte block */
    P1 = HEAP_ALLOC(24);
    OK = (P1 != 0);
    CALL CHK(OK, 2);

    /* 3: block has correct size */
    HP = P1;
    OK = (HP->OSIZE = 24);
    CALL CHK(OK, 3);

    /* 4: heap_top advanced */
    OK = (HEAP_TOP = HEAP_BASE + 24);
    CALL CHK(OK, 4);

    /* 5: second alloc is contiguous */
    P2 = HEAP_ALLOC(18);
    OK = (P2 = P1 + 24);
    CALL CHK(OK, 5);

    /* 6: heap_used correct */
    V = HEAP_USED();
    OK = (V = 42);
    CALL CHK(OK, 6);

    /* 7: free puts block on free list */
    CALL HEAP_FREE(P1);
