/* ================================================================
 * Heap walker
 *
 * Walks contiguous heap blocks from BASE to TOP, dumping each.
 * Returns number of blocks visited.
 * ================================================================ */

DCL HW_PFX(16) CHAR INIT('--- heap walk');
DCL HW_BLK(8) CHAR INIT(' blks=');
DCL HW_END(8) CHAR INIT('--- end');

HEAP_WALK: PROC(BASE PTR, TOP PTR) RETURNS(INT);
    DCL P PTR;
    DCL HP PTR;
    DCL SZ INT;
    DCL COUNT INT;

    CALL UART_PUTS(ADDR(HW_PFX));
    CALL PUT_NL;

    P = BASE;
    COUNT = 0;
    DO WHILE (P < TOP);
        HP = P;
        SZ = HP->OSIZE;
        /* Safety: if size is 0 or negative, stop to avoid infinite loop */
        IF (SZ < HDR_BYTES) THEN DO;
            DCL HW_ERR(20) CHAR INIT('ERR: bad size @');
            CALL UART_PUTS(ADDR(HW_ERR));
            CALL PUT_HEX24(P);
            CALL PUT_NL;
            RETURN(COUNT);
        END;
        CALL DUMP_HDR(P);
        COUNT = COUNT + 1;
        P = P + SZ;
    END;

    CALL UART_PUTS(ADDR(HW_END));
    CALL UART_PUTS(ADDR(HW_BLK));
    CALL PUT_HEX24(COUNT);
    CALL PUT_NL;
    RETURN(COUNT);
END;

/* ================================================================
 * Heap consistency checker
 *
 * Walks heap and checks:
 * 1. Each block size >= HDR_BYTES
 * 2. Each block kind is valid (< OBK_COUNT)
 * 3. Blocks don't overlap past TOP
 * Returns 0 if OK, error count if problems found.
 * ================================================================ */

DCL HC_OK(8) CHAR INIT('HEAP OK');
DCL HC_ERR(16) CHAR INIT('HEAP ERR: ');
DCL HC_BADSZ(16) CHAR INIT('bad size @');
DCL HC_BADKND(16) CHAR INIT('bad kind @');
DCL HC_OVER(16) CHAR INIT('overflow @');

HEAP_CHECK: PROC(BASE PTR, TOP PTR) RETURNS(INT);
    DCL P PTR;
    DCL HP PTR;
    DCL SZ INT;
    DCL K INT;
    DCL ERRS INT;

    P = BASE;
    ERRS = 0;
    DO WHILE (P < TOP);
        HP = P;
        SZ = HP->OSIZE;
        K = HP->OKIND;

        /* Check size */
        IF (SZ < HDR_BYTES) THEN DO;
            CALL UART_PUTS(ADDR(HC_ERR));
            CALL UART_PUTS(ADDR(HC_BADSZ));
            CALL PUT_HEX24(P);
            CALL PUT_NL;
            ERRS = ERRS + 1;
            RETURN(ERRS);
        END;

        /* Check kind */
        IF (K >= OBK_COUNT) THEN DO;
            CALL UART_PUTS(ADDR(HC_ERR));
            CALL UART_PUTS(ADDR(HC_BADKND));
            CALL PUT_HEX24(P);
            CALL PUT_NL;
            ERRS = ERRS + 1;
        END;

        /* Check overflow */
        IF (P + SZ > TOP) THEN DO;
            CALL UART_PUTS(ADDR(HC_ERR));
            CALL UART_PUTS(ADDR(HC_OVER));
            CALL PUT_HEX24(P);
            CALL PUT_NL;
            ERRS = ERRS + 1;
            RETURN(ERRS);
        END;

        P = P + SZ;
    END;

    IF (ERRS = 0) THEN DO;
        CALL UART_PUTS(ADDR(HC_OK));
        CALL PUT_NL;
    END;
    RETURN(ERRS);
END;

