/* test_dump.plsw -- Test descriptor dumper, heap walker, heap checker
 *
 * Visual output tests -- verify dump format by inspection.
 * Also tests HEAP_WALK return count and HEAP_CHECK return 0.
 */

%INCLUDE descr;
%INCLUDE heap;
%INCLUDE trace;

/* ---- Subset of snolib needed for this test ---- */

DCL TN_NULL(8) CHAR INIT('null');
DCL TN_INT(8) CHAR INIT('int');
DCL TN_STR(8) CHAR INIT('str');
DCL TN_UNK(8) CHAR INIT('???');

TAG_NAME: PROC(T INT) RETURNS(INT);
    IF (T = TAG_NULL) THEN RETURN(ADDR(TN_NULL));
    IF (T = TAG_INT) THEN RETURN(ADDR(TN_INT));
    IF (T = TAG_STR) THEN RETURN(ADDR(TN_STR));
    RETURN(ADDR(TN_UNK));
END;

DCL KN_FREE(8) CHAR INIT('free');
DCL KN_STRING(8) CHAR INIT('string');
DCL KN_SYMCELL(8) CHAR INIT('symcell');
DCL KN_UNK(8) CHAR INIT('???');

KIND_NAME: PROC(K INT) RETURNS(INT);
    IF (K = OBK_FREE) THEN RETURN(ADDR(KN_FREE));
    IF (K = OBK_STRING) THEN RETURN(ADDR(KN_STRING));
    IF (K = OBK_SYMCELL) THEN RETURN(ADDR(KN_SYMCELL));
    RETURN(ADDR(KN_UNK));
END;

DCL HEXCHARS(16) CHAR INIT('0123456789ABCDEF');

PUT_HEX_BYTE: PROC(V INT);
    DCL HI INT;
    DCL LO INT;
    HI = V;
    LO = 0;
    DO WHILE (HI > 15);
        HI = HI - 16;
        LO = LO + 1;
    END;
    CALL UART_PUTCHAR(HEXCHARS(LO));
    CALL UART_PUTCHAR(HEXCHARS(HI));
END;

PUT_HEX24: PROC(V INT);
    DCL B2 INT;
    DCL B1 INT;
    DCL B0 INT;
    DCL REM INT;
    REM = V;
    B2 = 0;
    DO WHILE (REM > 65535);
        REM = REM - 65536;
        B2 = B2 + 1;
    END;
    B1 = 0;
    DO WHILE (REM > 255);
        REM = REM - 256;
        B1 = B1 + 1;
    END;
    B0 = REM;
    CALL PUT_HEX_BYTE(B2);
    CALL PUT_HEX_BYTE(B1);
    CALL PUT_HEX_BYTE(B0);
END;

DCL NL_STR(3) CHAR INIT('
');
PUT_NL: PROC;
    CALL UART_PUTS(ADDR(NL_STR));
END;

/* ---- Dump procedures ---- */

DCL DD_PFX(8) CHAR INIT('DESC @');
DCL DD_TAG(8) CHAR INIT(' tag=');
DCL DD_SUB(8) CHAR INIT(' sub=');
DCL DD_PAY(8) CHAR INIT(' pay=');

DUMP_DESC: PROC(P PTR);
    DCL DP PTR;
    DP = P;
    CALL UART_PUTS(ADDR(DD_PFX));
    CALL PUT_HEX24(P);
    CALL UART_PUTS(ADDR(DD_TAG));
    CALL UART_PUTS(TAG_NAME(DP->DTAG));
    CALL UART_PUTS(ADDR(DD_SUB));
    CALL PUT_HEX_BYTE(DP->DSUB);
    CALL UART_PUTS(ADDR(DD_PAY));
    CALL PUT_HEX24(DP->DPAY);
    CALL PUT_NL;
END;

DCL HD_PFX(8) CHAR INIT('OBJ @');
DCL HD_KIND(8) CHAR INIT(' kind=');
DCL HD_SIZE(8) CHAR INIT(' size=');
DCL HD_FLAG(8) CHAR INIT(' fl=');

DUMP_HDR: PROC(P PTR);
    DCL HP PTR;
    HP = P;
    CALL UART_PUTS(ADDR(HD_PFX));
    CALL PUT_HEX24(P);
    CALL UART_PUTS(ADDR(HD_KIND));
    CALL UART_PUTS(KIND_NAME(HP->OKIND));
    CALL UART_PUTS(ADDR(HD_SIZE));
    CALL PUT_HEX24(HP->OSIZE);
    CALL UART_PUTS(ADDR(HD_FLAG));
    CALL PUT_HEX_BYTE(HP->OFLAGS);
    CALL PUT_NL;
END;

DCL HW_PFX(16) CHAR INIT('--- heap walk');
DCL HW_BLK(8) CHAR INIT(' blks=');
DCL HW_END(8) CHAR INIT('--- end');

HEAP_WALK: PROC(BASE PTR, TOP PTR) RETURNS(INT);
    DCL P PTR;
    DCL HP PTR;
    DCL SZ INT;
    DCL COUNT INT;
    CALL UART_PUTS(ADDR(HW_PFX));
    CALL PUT_NL;
    P = BASE;
    COUNT = 0;
    DO WHILE (P < TOP);
        HP = P;
        SZ = HP->OSIZE;
        IF (SZ < HDR_BYTES) THEN DO;
            RETURN(COUNT);
        END;
        CALL DUMP_HDR(P);
        COUNT = COUNT + 1;
        P = P + SZ;
    END;
    CALL UART_PUTS(ADDR(HW_END));
    CALL UART_PUTS(ADDR(HW_BLK));
    CALL PUT_HEX24(COUNT);
    CALL PUT_NL;
    RETURN(COUNT);
END;

DCL HC_OK(8) CHAR INIT('HEAP OK');

HEAP_CHECK: PROC(BASE PTR, TOP PTR) RETURNS(INT);
    DCL P PTR;
    DCL HP PTR;
    DCL SZ INT;
    DCL K INT;
    DCL ERRS INT;
    P = BASE;
    ERRS = 0;
    DO WHILE (P < TOP);
        HP = P;
        SZ = HP->OSIZE;
        K = HP->OKIND;
        IF (SZ < HDR_BYTES) THEN DO;
            ERRS = ERRS + 1;
            RETURN(ERRS);
        END;
        IF (K >= OBK_COUNT) THEN
            ERRS = ERRS + 1;
        IF (P + SZ > TOP) THEN DO;
            ERRS = ERRS + 1;
            RETURN(ERRS);
        END;
        P = P + SZ;
    END;
    IF (ERRS = 0) THEN DO;
        CALL UART_PUTS(ADDR(HC_OK));
        CALL PUT_NL;
    END;
    RETURN(ERRS);
END;

/* ---- Test data ---- */

DCL D1(6) BYTE;
DCL D2(6) BYTE;
DCL ARENA(256) BYTE;

DCL M_P(4) CHAR INIT('P ');
DCL M_F(4) CHAR INIT('F ');

CHK: PROC(OK INT, N INT);
    IF (OK != 0) THEN
        CALL UART_PUTS(ADDR(M_P));
    ELSE
        CALL UART_PUTS(ADDR(M_F));
    CALL UART_PUTCHAR(48 + N);
    CALL PUT_NL;
END;

/* ---- Main ---- */

MAIN: PROC;
    DCL DP PTR;
    DCL HP PTR;
    DCL OK INT;
    DCL V INT;

    /* Build some descriptors */
    DP = ADDR(D1);
    DP->DTAG = TAG_NULL;
    DP->DSUB = 0;
    DP->DRSV = 0;
    DP->DPAY = 0;

    DP = ADDR(D2);
    DP->DTAG = TAG_INT;
    DP->DSUB = 0;
    DP->DRSV = 0;
    DP->DPAY = 42;

    /* 1: dump null descriptor */
    CALL DUMP_DESC(ADDR(D1));

    /* 2: dump int descriptor */
    CALL DUMP_DESC(ADDR(D2));

    /* Build a small heap with 3 objects */
    HP = ADDR(ARENA);
    HP->OKIND = OBK_STRING;
    HP->OFLAGS = 0;
    HP->ORSV = 0;
    HP->OSIZE = 24;

    HP = ADDR(ARENA) + 24;
    HP->OKIND = OBK_SYMCELL;
    HP->OFLAGS = 0;
    HP->ORSV = 0;
    HP->OSIZE = 15;

    HP = ADDR(ARENA) + 39;
    HP->OKIND = OBK_FREE;
    HP->OFLAGS = 0;
    HP->ORSV = 0;
    HP->OSIZE = 30;

    /* 3: walk heap -- should find 3 blocks */
    V = HEAP_WALK(ADDR(ARENA), ADDR(ARENA) + 69);
    OK = (V = 3);
    CALL CHK(OK, 3);

    /* 4: check heap -- should return 0 errors */
    V = HEAP_CHECK(ADDR(ARENA), ADDR(ARENA) + 69);
    OK = (V = 0);
    CALL CHK(OK, 4);

    DCL M_DONE(20) CHAR INIT('All tests done');
    CALL UART_PUTS(ADDR(M_DONE));
    CALL PUT_NL;
END;

