/* test_walk.plsw -- Integration test: allocator + walker + checker
 *
 * Allocates objects, walks the heap, checks consistency,
 * frees a block, and verifies the walker still works.
 */

%INCLUDE descr;
%INCLUDE heap;

/* ---- snolib subset: allocator ---- */

DCL ARENA(512) BYTE;
DCL HEAP_BASE PTR STATIC;
DCL HEAP_LIM PTR STATIC;
DCL HEAP_TOP PTR STATIC;
DCL FREE_HD PTR STATIC INIT(0);
DCL ALLOC_N INT STATIC INIT(0);
DCL FREE_N INT STATIC INIT(0);

HEAP_INIT: PROC;
    HEAP_BASE = ADDR(ARENA);
    HEAP_LIM = ADDR(ARENA) + 512;
    HEAP_TOP = HEAP_BASE;
    FREE_HD = 0;
    ALLOC_N = 0;
    FREE_N = 0;
END;

HEAP_ALLOC: PROC(SZ INT) RETURNS(INT);
    DCL P PTR;
    DCL PREV PTR;
    DCL FP PTR;
    DCL PV PTR;
    DCL BS INT;
    IF (SZ < MIN_BLK) THEN
        SZ = MIN_BLK;
    P = FREE_HD;
    PREV = 0;
    DO WHILE (P != 0);
        FP = P;
        BS = FP->FS;
        IF (BS >= SZ) THEN DO;
            IF (PREV = 0) THEN
                FREE_HD = FP->FNEXT;
            ELSE DO;
                PV = PREV;
                PV->FNEXT = FP->FNEXT;
            END;
            ALLOC_N = ALLOC_N + 1;
            RETURN(P);
        END;
        PREV = P;
        FP = P;
        P = FP->FNEXT;
    END;
    IF (HEAP_TOP + SZ > HEAP_LIM) THEN
        RETURN(0);
    P = HEAP_TOP;
    FP = P;
    FP->FK = 0;
    FP->FF = 0;
    FP->FR = 0;
    FP->FS = SZ;
    HEAP_TOP = HEAP_TOP + SZ;
    ALLOC_N = ALLOC_N + 1;
    RETURN(P);
END;

HEAP_FREE: PROC(P PTR);
    DCL FP PTR;
    FP = P;
    FP->FK = OBK_FREE;
    FP->FF = 0;
    FP->FNEXT = FREE_HD;
    FREE_HD = P;
    FREE_N = FREE_N + 1;
END;

/* ---- snolib subset: diagnostics ---- */

DCL KN_FREE(8) CHAR INIT('free');
DCL KN_STRING(8) CHAR INIT('string');
DCL KN_SYMCELL(8) CHAR INIT('symcell');
