DCL M_P(4) CHAR INIT('P ');
DCL M_F(4) CHAR INIT('F ');
DCL M_DONE(20) CHAR INIT('All tests done');

CHK: PROC(OK INT, N INT);
    IF (OK != 0) THEN
        CALL UART_PUTS(ADDR(M_P));
    ELSE
        CALL UART_PUTS(ADDR(M_F));
    CALL UART_PUTCHAR(48 + N);
    CALL UART_PUTS(ADDR(M_NL));
END;

/* ---- Main ---- */

MAIN: PROC;
    DCL P1 PTR;
    DCL P2 PTR;
    DCL P3 PTR;
    DCL HP PTR;
    DCL OK INT;
    DCL V INT;

    CALL HEAP_INIT;

    /* Allocate 3 objects with proper kinds */
    P1 = HEAP_ALLOC(24);
    HP = P1;
    HP->OKIND = OBK_STRING;

    P2 = HEAP_ALLOC(15);
    HP = P2;
    HP->OKIND = OBK_SYMCELL;

    P3 = HEAP_ALLOC(18);
    HP = P3;
    HP->OKIND = OBK_STRING;

    /* 1: walk finds 3 blocks */
    V = HEAP_WALK(HEAP_BASE, HEAP_TOP);
    OK = (V = 3);
    CALL CHK(OK, 1);

    /* 2: check passes */
    V = HEAP_CHECK(HEAP_BASE, HEAP_TOP);
    OK = (V = 0);
    CALL CHK(OK, 2);

    /* 3: free middle block, walk still finds 3 (kind=free now) */
    CALL HEAP_FREE(P2);
    V = HEAP_WALK(HEAP_BASE, HEAP_TOP);
    OK = (V = 3);
    CALL CHK(OK, 3);

    /* 4: check still passes (free is valid kind) */
    V = HEAP_CHECK(HEAP_BASE, HEAP_TOP);
    OK = (V = 0);
    CALL CHK(OK, 4);

    /* 5: allocate a 4th object */
    P2 = HEAP_ALLOC(12);
    HP = P2;
    HP->OKIND = OBK_SYMCELL;
    V = HEAP_WALK(HEAP_BASE, HEAP_TOP);
    OK = (V = 4);
    CALL CHK(OK, 5);

    /* 6: full check on 4 blocks */
    V = HEAP_CHECK(HEAP_BASE, HEAP_TOP);
    OK = (V = 0);
    CALL CHK(OK, 6);

