/* test_walk.plsw -- Integration test: allocator + walker + checker
 *
 * Allocates objects, walks the heap, checks consistency,
 * frees a block, and verifies the walker still works.
 */

%INCLUDE descr;
%INCLUDE heap;

/* ---- snolib subset: allocator ---- */

DCL ARENA(512) BYTE;
DCL HEAP_BASE PTR STATIC;
DCL HEAP_LIM PTR STATIC;
DCL HEAP_TOP PTR STATIC;
DCL FREE_HD PTR STATIC INIT(0);
DCL ALLOC_N INT STATIC INIT(0);
DCL FREE_N INT STATIC INIT(0);

HEAP_INIT: PROC;
    HEAP_BASE = ADDR(ARENA);
    HEAP_LIM = ADDR(ARENA) + 512;
    HEAP_TOP = HEAP_BASE;
    FREE_HD = 0;
    ALLOC_N = 0;
    FREE_N = 0;
END;

HEAP_ALLOC: PROC(SZ INT) RETURNS(INT);
    DCL P PTR;
    DCL PREV PTR;
    DCL FP PTR;
    DCL PV PTR;
    DCL BS INT;
    IF (SZ < MIN_BLK) THEN
        SZ = MIN_BLK;
    P = FREE_HD;
    PREV = 0;
    DO WHILE (P != 0);
        FP = P;
        BS = FP->FS;
        IF (BS >= SZ) THEN DO;
            IF (PREV = 0) THEN
                FREE_HD = FP->FNEXT;
            ELSE DO;
                PV = PREV;
                PV->FNEXT = FP->FNEXT;
            END;
            ALLOC_N = ALLOC_N + 1;
            RETURN(P);
        END;
        PREV = P;
        FP = P;
        P = FP->FNEXT;
    END;
    IF (HEAP_TOP + SZ > HEAP_LIM) THEN
        RETURN(0);
    P = HEAP_TOP;
    FP = P;
    FP->FK = 0;
    FP->FF = 0;
    FP->FR = 0;
    FP->FS = SZ;
    HEAP_TOP = HEAP_TOP + SZ;
    ALLOC_N = ALLOC_N + 1;
    RETURN(P);
END;

HEAP_FREE: PROC(P PTR);
    DCL FP PTR;
    FP = P;
    FP->FK = OBK_FREE;
    FP->FF = 0;
    FP->FNEXT = FREE_HD;
    FREE_HD = P;
    FREE_N = FREE_N + 1;
END;

/* ---- snolib subset: diagnostics ---- */

DCL KN_FREE(8) CHAR INIT('free');
DCL KN_STRING(8) CHAR INIT('string');
DCL KN_SYMCELL(8) CHAR INIT('symcell');
DCL KN_UNK(8) CHAR INIT('???');

KIND_NAME: PROC(K INT) RETURNS(INT);
    IF (K = OBK_FREE) THEN RETURN(ADDR(KN_FREE));
    IF (K = OBK_STRING) THEN RETURN(ADDR(KN_STRING));
    IF (K = OBK_SYMCELL) THEN RETURN(ADDR(KN_SYMCELL));
    RETURN(ADDR(KN_UNK));
END;

DCL HEXCHARS(16) CHAR INIT('0123456789ABCDEF');

PUT_HEX_BYTE: PROC(V INT);
    DCL HI INT;
    DCL LO INT;
    HI = V;
    LO = 0;
    DO WHILE (HI > 15);
        HI = HI - 16;
        LO = LO + 1;
    END;
    CALL UART_PUTCHAR(HEXCHARS(LO));
    CALL UART_PUTCHAR(HEXCHARS(HI));
END;

PUT_HEX24: PROC(V INT);
    DCL B2 INT;
    DCL B1 INT;
    DCL B0 INT;
    DCL REM INT;
    REM = V;
    B2 = 0;
    DO WHILE (REM > 65535);
        REM = REM - 65536;
        B2 = B2 + 1;
    END;
    B1 = 0;
    DO WHILE (REM > 255);
        REM = REM - 256;
        B1 = B1 + 1;
    END;
    B0 = REM;
    CALL PUT_HEX_BYTE(B2);
    CALL PUT_HEX_BYTE(B1);
    CALL PUT_HEX_BYTE(B0);
END;

DCL M_NL(3) CHAR INIT('
');

DCL HD_PFX(8) CHAR INIT('OBJ @');
DCL HD_KIND(8) CHAR INIT(' kind=');
DCL HD_SIZE(8) CHAR INIT(' size=');
DCL HD_FLAG(8) CHAR INIT(' fl=');

DUMP_HDR: PROC(P PTR);
    DCL HP PTR;
    HP = P;
    CALL UART_PUTS(ADDR(HD_PFX));
    CALL PUT_HEX24(P);
    CALL UART_PUTS(ADDR(HD_KIND));
    CALL UART_PUTS(KIND_NAME(HP->OKIND));
    CALL UART_PUTS(ADDR(HD_SIZE));
    CALL PUT_HEX24(HP->OSIZE);
    CALL UART_PUTS(ADDR(HD_FLAG));
    CALL PUT_HEX_BYTE(HP->OFLAGS);
    CALL UART_PUTS(ADDR(M_NL));
END;

DCL HW_HDR(16) CHAR INIT('--- heap walk');
DCL HW_BLK(8) CHAR INIT(' blks=');
DCL HW_END(8) CHAR INIT('--- end');

HEAP_WALK: PROC(BASE PTR, TOP PTR) RETURNS(INT);
    DCL P PTR;
    DCL HP PTR;
    DCL SZ INT;
    DCL N INT;
    CALL UART_PUTS(ADDR(HW_HDR));
    CALL UART_PUTS(ADDR(M_NL));
    P = BASE;
    N = 0;
    DO WHILE (P < TOP);
        HP = P;
        SZ = HP->OSIZE;
        IF (SZ < HDR_BYTES) THEN
            RETURN(N);
        CALL DUMP_HDR(P);
        N = N + 1;
        P = P + SZ;
    END;
    CALL UART_PUTS(ADDR(HW_END));
    CALL UART_PUTS(ADDR(HW_BLK));
    CALL PUT_HEX24(N);
    CALL UART_PUTS(ADDR(M_NL));
    RETURN(N);
END;

DCL HC_OK(8) CHAR INIT('HEAP OK');

HEAP_CHECK: PROC(BASE PTR, TOP PTR) RETURNS(INT);
    DCL P PTR;
    DCL HP PTR;
    DCL SZ INT;
    DCL K INT;
    DCL E INT;
    P = BASE;
    E = 0;
    DO WHILE (P < TOP);
        HP = P;
        SZ = HP->OSIZE;
        K = HP->OKIND;
        IF (SZ < HDR_BYTES) THEN DO;
            E = E + 1;
            RETURN(E);
        END;
        IF (K >= OBK_COUNT) THEN
            E = E + 1;
        IF (P + SZ > TOP) THEN DO;
            E = E + 1;
            RETURN(E);
        END;
        P = P + SZ;
    END;
    IF (E = 0) THEN DO;
        CALL UART_PUTS(ADDR(HC_OK));
        CALL UART_PUTS(ADDR(M_NL));
    END;
    RETURN(E);
END;

/* ---- Test infra ---- */

DCL M_P(4) CHAR INIT('P ');
DCL M_F(4) CHAR INIT('F ');
DCL M_DONE(20) CHAR INIT('All tests done');

CHK: PROC(OK INT, N INT);
    IF (OK != 0) THEN
        CALL UART_PUTS(ADDR(M_P));
    ELSE
        CALL UART_PUTS(ADDR(M_F));
    CALL UART_PUTCHAR(48 + N);
    CALL UART_PUTS(ADDR(M_NL));
END;

/* ---- Main ---- */

MAIN: PROC;
    DCL P1 PTR;
    DCL P2 PTR;
    DCL P3 PTR;
    DCL HP PTR;
    DCL OK INT;
    DCL V INT;

    CALL HEAP_INIT;

    /* Allocate 3 objects with proper kinds */
    P1 = HEAP_ALLOC(24);
    HP = P1;
    HP->OKIND = OBK_STRING;

    P2 = HEAP_ALLOC(15);
    HP = P2;
    HP->OKIND = OBK_SYMCELL;

    P3 = HEAP_ALLOC(18);
    HP = P3;
    HP->OKIND = OBK_STRING;

    /* 1: walk finds 3 blocks */
    V = HEAP_WALK(HEAP_BASE, HEAP_TOP);
    OK = (V = 3);
    CALL CHK(OK, 1);

    /* 2: check passes */
    V = HEAP_CHECK(HEAP_BASE, HEAP_TOP);
    OK = (V = 0);
    CALL CHK(OK, 2);

    /* 3: free middle block, walk still finds 3 (kind=free now) */
    CALL HEAP_FREE(P2);
    V = HEAP_WALK(HEAP_BASE, HEAP_TOP);
    OK = (V = 3);
    CALL CHK(OK, 3);

    /* 4: check still passes (free is valid kind) */
    V = HEAP_CHECK(HEAP_BASE, HEAP_TOP);
    OK = (V = 0);
    CALL CHK(OK, 4);

    /* 5: realloc reuses freed block (still 3 contiguous blocks) */
    P2 = HEAP_ALLOC(12);
    HP = P2;
    HP->OKIND = OBK_SYMCELL;
    V = HEAP_WALK(HEAP_BASE, HEAP_TOP);
    OK = (V = 3);
    CALL CHK(OK, 5);

    /* 6: check passes after reuse */
    V = HEAP_CHECK(HEAP_BASE, HEAP_TOP);
    OK = (V = 0);
    CALL CHK(OK, 6);

    /* 7: new bump alloc creates 4th block */
    P2 = HEAP_ALLOC(20);
    HP = P2;
    HP->OKIND = OBK_STRING;
    V = HEAP_WALK(HEAP_BASE, HEAP_TOP);
    OK = (V = 4);
    CALL CHK(OK, 7);

    CALL UART_PUTS(ADDR(M_DONE));
    CALL UART_PUTS(ADDR(M_NL));
END;

